from typing import Protocol, runtime_checkable
from collections.abc import Iterator

# ─── 1. Simple Protocol ───────────────────────────────────────────────────────
class Closeable(Protocol):
    """Any object that can be closed."""
    def close(self) -> None:
        ...

def safe_close(resource: Closeable) -> None:
    """Close any closeable resource."""
    try:
        resource.close()
        print(f"Closed {type(resource).__name__}")
    except Exception as e:
        print(f"Error closing: {e}")

# These classes don't inherit from Closeable, but both satisfy it:
class FileWrapper:
    def __init__(self, path: str) -> None:
        self.path = path

    def close(self) -> None:
        print(f"Closing file: {self.path}")

class DatabaseConnection:
    def close(self) -> None:
        print("Closing DB connection")

safe_close(FileWrapper("/tmp/data.csv"))  # Works!
safe_close(DatabaseConnection())          # Works!
# mypy is happy because both classes have close() -> None

# ─── 2. Protocol with attributes and methods ──────────────────────────────────
class Drawable(Protocol):
    """A renderable object with a position."""
    x: float
    y: float

    def draw(self) -> None:
        ...

    def get_bounds(self) -> tuple[float, float, float, float]:
        """Return (min_x, min_y, max_x, max_y)."""
        ...

class Circle:
    def __init__(self, x: float, y: float, radius: float) -> None:
        self.x = x
        self.y = y
        self.radius = radius

    def draw(self) -> None:
        print(f"Drawing circle at ({self.x}, {self.y}) r={self.radius}")

    def get_bounds(self) -> tuple[float, float, float, float]:
        r = self.radius
        return (self.x - r, self.y - r, self.x + r, self.y + r)

class Rectangle:
    def __init__(self, x: float, y: float, width: float, height: float) -> None:
        self.x = x
        self.y = y
        self.width = width
        self.height = height

    def draw(self) -> None:
        print(f"Drawing rect at ({self.x}, {self.y}) {self.width}x{self.height}")

    def get_bounds(self) -> tuple[float, float, float, float]:
        return (self.x, self.y, self.x + self.width, self.y + self.height)

def render_scene(objects: list[Drawable]) -> None:
    """Render a list of drawable objects."""
    for obj in objects:
        obj.draw()

# Mix Circles and Rectangles — both satisfy Drawable Protocol
scene: list[Drawable] = [
    Circle(100, 100, 50),
    Rectangle(200, 150, 80, 60),
    Circle(300, 200, 30),
]
render_scene(scene)

from typing import Protocol, runtime_checkable

@runtime_checkable
class Serializable(Protocol):
    """Objects that can serialize themselves to a string."""
    def serialize(self) -> str:
        ...

class Config:
    def __init__(self, data: dict) -> None:
        self.data = data

    def serialize(self) -> str:
        import json
        return json.dumps(self.data)

class Logger:
    def __init__(self, name: str) -> None:
        self.name = name

    def serialize(self) -> str:
        return f"Logger(name={self.name!r})"

class NoSerialize:
    pass  # does not implement serialize()

# Runtime isinstance check
for obj in [Config({"a": 1}), Logger("main"), NoSerialize()]:
    if isinstance(obj, Serializable):  # works with @runtime_checkable
        print(f"{type(obj).__name__}: {obj.serialize()}")
    else:
        print(f"{type(obj).__name__}: not serializable")

# Note: isinstance only checks method presence, not signature!
# A class with def serialize(self, extra_arg) -> str also passes

from typing import TypeVar, Protocol, Generic
from collections.abc import Callable

# Define a Protocol for comparable types
class SupportsLessThan(Protocol):
    def __lt__(self, other: object) -> bool:
        ...

Comparable = TypeVar("Comparable", bound=SupportsLessThan)

def binary_search(
    sequence: list[Comparable],
    target: Comparable,
) -> int:
    """Return index of target in sorted sequence, or -1 if not found."""
    lo, hi = 0, len(sequence) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if sequence[mid] == target:
            return mid
        elif sequence[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

# Works for int, float, str — anything that supports < comparison
print(binary_search([1, 3, 5, 7, 9], 5))       # 2
print(binary_search(["a", "b", "d", "z"], "d")) # 2
print(binary_search([1.0, 2.5, 3.7], 2.5))      # 1

# Generic container with Protocol-based ordering
class SortedContainer(Generic[Comparable]):
    def __init__(self) -> None:
        self._items: list[Comparable] = []

    def add(self, item: Comparable) -> None:
        """Add item in sorted position."""
        import bisect
        bisect.insort(self._items, item)  # type: ignore[arg-type]

    def to_list(self) -> list[Comparable]:
        return list(self._items)

sc: SortedContainer[int] = SortedContainer()
sc.add(5); sc.add(2); sc.add(8); sc.add(1)
print(sc.to_list())  # [1, 2, 5, 8]

from typing import TypeVar, Protocol, Generic, runtime_checkable
from collections.abc import Iterator, Callable
from dataclasses import dataclass

T = TypeVar("T")
R = TypeVar("R")

# ─── Protocol: any data source that yields records ────────────────────────────
@runtime_checkable
class DataSource(Protocol[T]):
    """A source of typed data records."""
    def read_batch(self, batch_size: int) -> list[T]:
        ...

    def __iter__(self) -> Iterator[T]:
        ...

# ─── Generic pipeline stage ───────────────────────────────────────────────────
class Pipeline(Generic[T, R]):
    """A data pipeline that transforms T records into R records."""

    def __init__(
        self,
        source: DataSource[T],
        transform: Callable[[T], R],
    ) -> None:
        self.source = source
        self.transform = transform

    def process(self, batch_size: int = 100) -> list[R]:
        batch = self.source.read_batch(batch_size)
        return [self.transform(record) for record in batch]

# ─── Concrete implementations ─────────────────────────────────────────────────
@dataclass
class RawEvent:
    timestamp: float
    message: str

@dataclass
class ParsedEvent:
    timestamp: float
    level: str
    text: str

class LogFileSource:
    """Satisfies DataSource[RawEvent] via structural typing."""
    def __init__(self, path: str) -> None:
        self.path = path
        self._data = [
            RawEvent(1000.0, "INFO: Server started"),
            RawEvent(1001.0, "ERROR: Connection refused"),
            RawEvent(1002.0, "INFO: Retry succeeded"),
        ]

    def read_batch(self, batch_size: int) -> list[RawEvent]:
        return self._data[:batch_size]

    def __iter__(self) -> Iterator[RawEvent]:
        return iter(self._data)

def parse_event(raw: RawEvent) -> ParsedEvent:
    parts = raw.message.split(": ", 1)
    level, text = (parts[0], parts[1]) if len(parts) == 2 else ("INFO", parts[0])
    return ParsedEvent(timestamp=raw.timestamp, level=level, text=text)

# Pipeline is fully typed: Pipeline[RawEvent, ParsedEvent]
source = LogFileSource("/var/log/app.log")
pipeline: Pipeline[RawEvent, ParsedEvent] = Pipeline(source, parse_event)

events = pipeline.process(batch_size=10)
for e in events:
    print(f"[{e.level}] {e.text}")  # mypy knows e is ParsedEvent

# At runtime, isinstance check works because DataSource is runtime_checkable
print(isinstance(source, DataSource))  # True

from typing import Protocol, runtime_checkable

@runtime_checkable
class Greetable(Protocol):
    def greet(self, name: str) -> str:
        ...

class GoodGreeter:
    def greet(self, name: str) -> str:
        return f"Hello, {name}!"

class BadGreeter:
    def greet(self) -> str:  # wrong signature — no 'name' parameter!
        return "Hello!"

# Runtime isinstance check passes for both — it only checks method presence
print(isinstance(GoodGreeter(), Greetable))  # True
print(isinstance(BadGreeter(), Greetable))   # True — BUG!

# But mypy WILL catch the signature mismatch statically:
# def use(g: Greetable) -> str:
#     return g.greet("Alice")
# use(BadGreeter())  # mypy error: signature incompatible with Greetable

# Python 3.12+ new generic syntax (PEP 695)
# No need to import TypeVar or Generic

class Stack[T]:
    def __init__(self) -> None:
        self._items: list[T] = []

    def push(self, item: T) -> None:
        self._items.append(item)

    def pop(self) -> T:
        return self._items.pop()

def first[T](items: list[T]) -> T | None:
    return items[0] if items else None

